<?php
$esc = static fn($v) => htmlspecialchars((string) $v, ENT_QUOTES, 'UTF-8');
function yes_no_question(string $num, string $question, string $name, bool $showAbortAdvice = false): string
{
    $esc = static fn($v) => htmlspecialchars($v, ENT_QUOTES, 'UTF-8');
    ob_start();
    ?>
    <div class="question-card straight-question<?php echo $showAbortAdvice ? ' special-question' : ''; ?>">
      <div class="question-line">
        <span class="question-no"><?php echo $esc($num); ?>.</span>
        <div class="question-copy"><?php echo $esc($question); ?></div>
        <div class="choice-row">
          <label class="radio-option<?php echo $showAbortAdvice ? ' special-radio-yes' : ''; ?>"><input type="radio" name="<?php echo $esc($name); ?>" value="Yes"><span>Yes</span></label>
          <label class="radio-option"><input type="radio" name="<?php echo $esc($name); ?>" value="No"><span>No</span></label>
        </div>
      </div>
      <?php if ($showAbortAdvice): ?>
        <div class="abort-advice" hidden>Please abort and reschedule test with advice.</div>
      <?php endif; ?>
    </div>
    <?php
    return trim((string) ob_get_clean());
}
function frequency_question(string $num, string $question, string $name, array $choices): string
{
    $esc = static fn($v) => htmlspecialchars($v, ENT_QUOTES, 'UTF-8');
    ob_start();
    ?>
    <div class="question-card straight-question frequency-question">
      <div class="question-line frequency-line">
        <span class="question-no"><?php echo $esc($num); ?>.</span>
        <div class="question-copy"><?php echo $esc($question); ?></div>
        <div class="stack-options inline-stack-options">
          <?php foreach ($choices as $choice): ?>
            <label class="radio-block inline-radio-block"><input type="radio" name="<?php echo $esc($name); ?>" value="<?php echo $esc($choice); ?>"><span><?php echo $esc($choice); ?></span></label>
          <?php endforeach; ?>
        </div>
      </div>
    </div>
    <?php
    return trim((string) ob_get_clean());
}
