e-columns:auto minmax(0,1fr) auto}.question-no{font-weight:700;color:#166534;flex-shrink:0}.question-copy{font-size:.95rem;line-height:1.45;color:#111827}.choice-row{display:flex;gap:24px;align-items:center;flex-wrap:nowrap;padding-left:0}.radio-option,.radio-block{display:inline-flex;align-items:center;gap:10px;color:#111827;white-space:nowrap}.radio-option input,.radio-block input,.inline-check input{width:18px;height:18px;accent-color:#389B5B}.special-radio-yes input{accent-color:#dc2626}.abort-advice{margin-left:36px;color:#b91c1c;font-size:.9rem;font-weight:600}.stack-options{display:grid;gap:10px}.inline-stack-options{display:flex;gap:16px;align-items:center;flex-wrap:nowrap}.radio-block{padding:10px 12px;border:1px solid #e5e7eb;border-radius:12px;background:#fff}.inline-radio-block{padding:0;border:0;background:transparent}.test-grid{display:grid;grid-template-columns:minmax(0,1.12fr) minmax(420px,.88fr);gap:12px;align-items:start}.test-stack{display:grid;gap:12px}.mini-panel,.technician-panel{border:1px solid #e5e7eb;border-radius:14px;background:#fafafa}.mini-panel{padding:12px}.test-compact{min-height:auto}.visual-compact{min-height:86px}.technician-panel{display:grid;grid-template-rows:auto auto 1fr auto 1px auto;align-self:stretch;padding:12px;height:100%}.technician-signature{padding:0}.technician-name{padding:0}.technician-divider{height:1px;background:#e5e7eb;margin:12px -12px}.technician-panel .field{display:block}.signature-pad-wrap{margin-top:6px;display:flex;flex-direction:column}.signature-pad{width:100%;height:270px;min-height:270px;border:2px solid #111827;border-radius:16px;background:#fff;display:block;touch-action:none;cursor:crosshair}.signature-actions{display:flex;justify-content:flex-end;margin-top:10px}.mini-panel h4,.technician-panel h4{margin:0 0 8px;font-size:.96rem}.audiometry-grid{display:grid;grid-template-columns:120px repeat(7,minmax(0,1fr));gap:6px 6px;align-items:center}.audiometry-grid .head-cell{font-size:.76rem;font-weight:700;color:#6b7280;text-transform:uppercase}.audiometry-grid .row-label{font-size:.82rem;font-weight:600;color:#1f2937}.audiometry-grid input{width:100%;border:1px solid #d7dce7;border-radius:10px;padding:6px 7px;background:#fff}.inline-check{display:inline-flex;align-items:center;gap:10px;margin-right:14px;margin-bottom:8px}.hidden-visual-detail{display:none}.hidden-visual-detail.is-visible{display:block}.actions{margin-top:18px;display:flex;justify-content:space-between;gap:8px;flex-wrap:wrap}.btn{border:1px solid #d1d5db;border-radius:10px;padding:10px 14px;background:#fff;color:#374151;text-decoration:none;font-size:.92rem;display:inline-flex;align-items:center;gap:6px;cursor:pointer}.btn.primary{background:var(--green);border-color:var(--green);color:#fff;font-weight:600}@media (max-width:980px){.grid,.question-grid,.test-grid{grid-template-columns:1fr}.test-grid{grid-template-areas:"audio" "visual" "technician"}.audiometry-grid{grid-template-columns:110px repeat(7,minmax(56px,1fr))}}@media (max-width:980px){.grid,.question-grid,.test-grid{grid-template-columns:1fr}.audiometry-grid{grid-template-columns:110px repeat(7,minmax(56px,1fr))}.question-line,.frequency-line{grid-template-columns:1fr}.straight-question .choice-row{padding-left:34px}.inline-stack-options{display:grid}}@media (max-width:760px){.overlay{padding:14px}.modal{padding:18px}.choice-row{gap:16px}}
</style></head>
<body>
<div class="overlay"><form class="modal" method="post" action="#" id="newQuestionnaireForm" novalidate><h1>New Questionnaire</h1><p class="muted">Fill in the audiometry questionnaire using the same clean system style as the other modal forms.</p><div class="intro"><strong>QUESTIONNAIRE FORM FOR AUDIOMETRIC TESTING</strong><span>Direct entry layout for questionnaire details and related audiometry notes.</span></div><div class="panel"><div class="section-head"><div><h3>Employee Details</h3><p>Basic employee and test information.</p></div><span class="pill">Part A</span></div><div class="grid"><label class="field">Name<input type="text" name="name" placeholder="Enter employee name"></label><label class="field">Gender<select name="gender"><option value="">Select gender</option><option>Male</option><option>Female</option></select></label><label class="field">Age<input type="text" name="age" placeholder="Enter age"></label><label class="field">Company<input type="text" name="company" placeholder="Enter company name"></label><label class="field">IC / Passport No<input type="text" name="passport_no" placeholder="Enter IC or passport number"></label><label class="field">Department<input type="text" name="department" placeholder="Enter department"></label><label class="field">Job<input type="text" name="job" placeholder="Enter job title"></label><label class="field">Years of Service<input type="text" name="years_of_service" placeholder="Enter years of service"></label><label class="field full">Test Date<input type="date" name="test_date"></label></div></div><div class="panel"><div class="section-head"><div><h3>Questionnaire</h3><p>Noise exposure, hearing history, and lifestyle screening.</p></div><span class="pill">Part B</span></div><div class="question-grid"><?php echo yes_no_question('1','Were you exposed to loud noise within 14 hours prior to today\'s test?','question_1', true); ?><?php echo yes_no_question('2','Have you suffered any illness that has affected your hearing (e.g. infection, tinnitus, discharge)?','question_2'); ?><?php echo yes_no_question('3','Have you ever had an ear operation or any other major operation that affected your hearing?','question_3'); ?><?php echo yes_no_question('4','Have you ever taken any medication (tablets or injection) that affected your hearing?','question_4'); ?><?php echo yes_no_question('5','Have you been exposed to loud noise (e.g. chainsaw, firecrackers, explosion, gunfire, motorcycles)?','question_5'); ?><?php echo yes_no_question('6','Any family history of hearing loss/disorders?','question_6'); ?><?php echo frequency_question('7','Do you attend night clubs/pubs/discotheques or pop/rock concerts?','question_7',['Never','Once a year','More than once a year']); ?><?php echo frequency_question('8','Do you use a personal stereo?','question_8',['Never','Less than 2 hours a week','More than 2 hours a week']); ?><?php echo yes_no_question('9','Do you play loud music instruments?','question_9'); ?><?php echo yes_no_question('10','Have you worked in noisy jobs in the past?','question_10'); ?><?php echo yes_no_question('11','Were you wearing personal hearing protectors at that time?','question_11'); ?><?php echo yes_no_question('12','Have you had an audiometric test before?','question_12'); ?></div></div><div class="panel"><div class="section-head"><div><h3>Audiometry Notes</h3><p>Optional test and supporting details.</p></div><span class="pill">Part C</span></div><div class="test-grid"><div class="test-stack"><div class="mini-panel test-compact"><h4>Audiometry Test</h4><div class="audiometry-grid"><div class="head-cell"></div><div class="head-cell">500</div><div class="head-cell">1K</div><div class="head-cell">2K</div><div class="head-cell">3K</div><div class="head-cell">4K</div><div class="head-cell">6K</div><div class="head-cell">8K</div><div class="row-label">Air Right</div><input type="text" name="air_right_500"><input type="text" name="air_right_1k"><input type="text" name="air_right_2k"><input type="text" name="air_right_3k"><input type="text" name="air_right_4k"><input type="text" name="air_right_6k"><input type="text" name="air_right_8k"><div class="row-label">Air Left</div><input type="text" name="air_left_500"><input type="text" name="air_left_1k"><input type="text" name="air_left_2k"><input type="text" name="air_left_3k"><input type="text" name="air_left_4k"><input type="text" name="air_left_6k"><input type="text" name="air_left_8k"><div class="row-label">Bone Right</div><input type="text" name="bone_right_500"><input type="text" name="bone_right_1k"><input type="text" name="bone_right_2k"><input type="text" name="bone_right_3k"><input type="text" name="bone_right_4k"><input type="text" name="bone_right_6k"><input type="text" name="bone_right_8k"><div class="row-label">Bone Left</div><input type="text" name="bone_left_500"><input type="text" name="bone_left_1k"><input type="text" name="bone_left_2k"><input type="text" name="bone_left_3k"><input type="text" name="bone_left_4k"><input type="text" name="bone_left_6k"><input type="text" name="bone_left_8k"></div></div><div class="mini-panel visual-compact"><h4>Visual Examination of Ear</h4><label class="inline-check"><input type="radio" name="visual_exam_status" value="Normal" id="visualExamNormal"><span>Normal</span></label><label class="inline-check"><input type="radio" name="visual_exam_status" value="Abnormal" id="visualExamAbnormal"><span>Abnormal</span></label><label class="field visual-detail hidden-visual-detail" id="visualExamDetail">If abnormal, please detail<textarea name="visual_details" id="visualDetails" placeholder="Add details" style="min-height:56px;"></textarea></label></div></div><div class="technician-panel"><div class="technician-signature"><h4>Audiometric Technician</h4><label class="field">Signature<div class="signature-pad-wrap"><canvas id="signaturePad" class="signature-pad" width="420" height="320"></canvas><input type="hidden" name="technician_signature" id="technicianSignature"><div class="signature-actions"><button type="button" class="btn" id="clearSignature">Clear</button></div></div></label></div><div class="technician-divider"></div><div class="technician-name"><label class="field">Name<input type="text" name="technician_name" placeholder="Enter technician name"></label></div></div></div></div><div class="actions"><a class="btn" href="audiometry_questionnaire.php">Cancel</a><button class="btn primary" type="submit">Save Questionnaire</button></div></form></div><script>(function(){const form=document.getElementById('newQuestionnaireForm');const q1Yes=document.querySelector('input[name="question_1"][value="Yes"]');const q1No=document.querySelector('input[name="question_1"][value="No"]');const q1Card=q1Yes?q1Yes.closest('.special-question'):null;const q1Advice=q1Card?q1Card.querySelector('.abort-advice'):null;const syncQuestion1=function(){if(!q1Yes||!q1Advice){return;}q1Advice.hidden=!q1Yes.checked;};if(q1Yes&&q1No){q1Yes.addEventListener('change',syncQuestion1);q1No.addEventListener('change',syncQuestion1);syncQuestion1();}const canvas=document.getElementById('signaturePad');const hiddenInput=document.getElementById('technicianSignature');const clearBtn=document.getElementById('clearSignature');if(canvas&&hiddenInput){const ctx=canvas.getContext('2d');let drawing=false;let activePointerId=null;const fillCanvas=function(){ctx.setTransform(1,0,0,1,0,0);ctx.clearRect(0,0,canvas.width,canvas.height);ctx.fillStyle='#ffffff';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.lineWidth=2;ctx.lineCap='round';ctx.lineJoin='round';ctx.strokeStyle='#111827';};const pointFromEvent=function(event){const rect=canvas.getBoundingClientRect();const scaleX=canvas.width/rect.width;const scaleY=canvas.height/rect.height;return{x:(event.clientX-rect.left)*scaleX,y:(event.clientY-rect.top)*scaleY};};const saveSignature=function(){hiddenInput.value=canvas.toDataURL('image/png');};const startDrawing=function(event){drawing=true;activePointerId=event.pointerId;try{canvas.setPointerCapture(activePointerId);}catch(e){}const point=pointFromEvent(event);ctx.beginPath();ctx.moveTo(point.x,point.y);event.preventDefault();};const draw=function(event){if(!drawing){return;}const point=pointFromEvent(event);ctx.lineTo(point.x,point.y);ctx.stroke();saveSignature();event.preventDefault();};const stopDrawing=function(event){if(!drawing){return;}drawing=false;if(activePointerId!==null){try{canvas.releasePointerCapture(activePointerId);}catch(e){}activePointerId=null;}saveSignature();if(event){event.preventDefault();}};fillCanvas();canvas.addEventListener('pointerdown',startDrawing);canvas.addEventListener('pointermove',draw);canvas.addEventListener('pointerup',stopDrawing);canvas.addEventListener('pointercancel',stopDrawing);if(clearBtn){clearBtn.addEventListener('click',function(){hiddenInput.value='';fillCanvas();});}}const visualNormal=document.getElementById('visualExamNormal');const visualAbnormal=document.getElementById('visualExamAbnormal');const visualDetail=document.getElementById('visualExamDetail');const visualDetails=document.getElementById('visualDetails');const syncVisualExam=function(){if(!visualAbnormal||!visualDetail||!visualDetails){return;}const isAbnormal=visualAbnormal.checked;visualDetail.classList.toggle('is-visible',isAbnormal);visualDetails.required=isAbnormal;if(!isAbnormal){visualDetails.value='';}};if(visualNormal&&visualAbnormal){visualNormal.addEventListener('change',syncVisualExam);visualAbnormal.addEventListener('change',syncVisualExam);syncVisualExam();}form.addEventListener('submit',function(e){if(!form.checkValidity()){e.preventDefault();form.reportValidity();}});}());</script></body></html>





























